    animation: wave 0.5s ease-in-out infinite;
  }

  .audio-wave .bar:nth-child(2) { animation-delay: 0.1s; }
  .audio-wave .bar:nth-child(3) { animation-delay: 0.2s; }
  .audio-wave .bar:nth-child(4) { animation-delay: 0.3s; }
  .audio-wave .bar:nth-child(5) { animation-delay: 0.4s; }
  .audio-wave .bar:nth-child(6) { animation-delay: 0.5s; }
  .audio-wave .bar:nth-child(7) { animation-delay: 0.4s; }
  .audio-wave .bar:nth-child(8) { animation-delay: 0.3s; }
  .audio-wave .bar:nth-child(9) { animation-delay: 0.2s; }
  .audio-wave .bar:nth-child(10) { animation-delay: 0.1s; }

  @keyframes wave {
    0% { height: 20%; }
    50% { height: 80%; }
    100% { height: 20%; }
  }

  .paused .bar {
    animation-play-state: paused;
  }
}

