                )}
              </div>
            ))
          ) : (
            <p>No modules found.</p>
          )}
        </div>
      </div>

      {/* Practice Areas */}
      <div className="mb-12">
        <h2 className="font-heading text-xl font-bold text-primary mb-6">Practice Your Skills</h2>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          {/* Sales Call Simulator */}
