client/src/components/modules/ModuleCont.content:
import React, { useState } from "react";
import { Link, useLocation } from "wouter";
import { Button } from "@/components/ui/button";
import { Card } from "@/components/ui/card";
import { CheckCircleIcon } from "@/assets/icons";
import { useToast } from "@/hooks/use-toast";

interface ModuleLesson {
  id: string;
  title: string;
  content: string;
  assignment?: string;
  reflection?: string;
}

interface ModuleContentProps {
  moduleId: number;
  moduleTitle: string;
  lessons: ModuleLesson[];
  isAuthenticated?: boolean;
}

const ModuleContent: React.FC<ModuleContentProps> = ({
  moduleId,
  moduleTitle,
  lessons,
  isAuthenticated = false
}) => {
  const [currentLessonIndex, setCurrentLessonIndex] = useState(0);
  const [completedLessons, setCompletedLessons] = useState<Record<string, boolean>>({});
  const [moduleCompleted, setModuleCompleted] = useState(false);
  const [, setLocation] = useLocation();
  const { toast } = useToast();

  const currentLesson = lessons[currentLessonIndex];
  // All modules and lessons are fully accessible

  const handleNextLesson = () => {
    // Mark current lesson as completed
    setCompletedLessons(prev => ({
      ...prev,
      [currentLesson.id]: true
    }));

    // Move to next lesson if available
    if (currentLessonIndex < lessons.length - 1) {
      setCurrentLessonIndex(currentLessonIndex + 1);
      window.scrollTo(0, 0);
    } else {
      // Module completed
      setModuleCompleted(true);
      toast({
        title: "Module Completed!",
        description: "You've completed this module. Great work!",
      });
    }
  };

  const handleNextModule = () => {
    const nextModuleId = moduleId + 1;
    // Check if next module exists (modules 1-6)
    if (nextModuleId <= 6) {
      setLocation(`/modules/${nextModuleId}`);
    } else {
      toast({
        title: "Congratulations!",
        description: "You've completed all available modules!",
      });
    }
  };

  const handlePreviousLesson = () => {
    if (currentLessonIndex > 0) {
      setCurrentLessonIndex(currentLessonIndex - 1);
      window.scrollTo(0, 0);
    }
  };

  const allLessonsCompleted = lessons.every(lesson => completedLessons[lesson.id]);

  return (
    <div className="max-w-4xl mx-auto">
      <div className="mb-8">
        <Link href="/" className="text-accent hover:text-accent-dark transition-colors">
          &larr; Back to Modules
        </Link>
        <h1 className="font-heading text-3xl font-bold text-primary mt-4 mb-2">
          {moduleTitle}
        </h1>
        <div className="flex items-center">
          <div className="h-1 bg-neutral-light rounded-full flex-grow">
            <div 
              className="h-full bg-primary rounded-full" 
              style={{ 
                width: `${(Object.keys(completedLessons).length / lessons.length) * 100}%` 
              }}
            />
          </div>
          <span className="text-sm text-neutral-medium ml-3">
            {Object.keys(completedLessons).length}/{lessons.length} completed
          </span>
        </div>
      </div>

      {/* Welcome message for all users */}
      <Card className="mb-6 bg-gradient-to-r from-green-50 to-blue-50 border-green-200">
        <div className="p-4">
          <div className="flex items-center">
            <div className="bg-green-100 p-2 rounded-full mr-3">
              <svg className="w-5 h-5 text-green-600" fill="currentColor" viewBox="0 0 20 20">
                <path fillRule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z" clipRule="evenodd" />
              </svg>
            </div>
            <div>
              <h3 className="font-semibold text-green-900">Full Access</h3>
              <p className="text-sm text-green-700">Complete lessons, assignments, and reflections - completely free.</p>
            </div>
          </div>
        </div>
      </Card>

      <div className="flex mb-8">
        <div className="w-64 hidden md:block pr-6 border-r border-neutral-light">
          <h3 className="font-medium text-lg mb-4">Lessons</h3>
          <ul className="space-y-3">
            {lessons.map((lesson, index) => (
              <li key={lesson.id}>
                <button
                  className={`flex items-center text-left w-full p-2 rounded-lg ${
                    currentLessonIndex === index
                      ? 'bg-primary text-white'
                      : completedLessons[lesson.id]
                        ? 'text-white bg-primary bg-opacity-80'
                        : 'text-neutral-medium hover:bg-neutral-lightest'
                  }`}
                  onClick={() => setCurrentLessonIndex(index)}
                >
                  {completedLessons[lesson.id] && (
                    <CheckCircleIcon className="h-4 w-4 mr-2 flex-shrink-0" />
                  )}
                  <span className={`text-sm ${!completedLessons[lesson.id] && 'ml-6'}`}>
                    {lesson.title}
                  </span>
                </button>
              </li>
            ))}
          </ul>
        </div>

        <div className="flex-1 md:pl-8">
          <div className="mb-6">
            <h2 className="font-heading text-2xl font-bold mb-6">
              {currentLesson.title}
            </h2>

            <div className="prose max-w-none">
              {currentLesson.content.split('\n\n').map((paragraph, idx) => (
                <p key={idx} className="mb-4">
                  {paragraph}
                </p>
              ))}
            </div>
          </div>

          {/* Encouragement for continued learning */}

          {currentLesson.assignment && (
            <Card className="p-6 mb-6 bg-secondary bg-opacity-20 border-secondary">
              <h3 className="font-heading text-lg font-bold mb-3">Assignment</h3>
              <div className="prose max-w-none">
                {currentLesson.assignment.split('\n\n').map((paragraph, idx) => (
                  <p key={idx} className="mb-4">
                    {paragraph}
                  </p>
                ))}
              </div>
            </Card>
          )}

          {currentLesson.reflection && (
            <div 
              className="p-6 mb-6 rounded-lg border shadow-sm" 
              style={{ 
                backgroundColor: '#f0fdf4 !important', 
                borderColor: '#bbf7d0 !important', 
                color: '#14532d !important'
              }}
            >
              <h3 className="font-heading text-lg font-bold mb-3" style={{ color: '#166534 !important' }}>Reflect</h3>
              <div className="prose max-w-none" style={{ color: '#14532d !important' }}>
                {currentLesson.reflection.split('\n\n').map((paragraph, idx) => (
                  <p key={idx} className="mb-4 font-medium" style={{ color: '#14532d !important' }}>
                    {paragraph}
                  </p>
                ))}
              </div>
            </div>
          )}

          <div className="flex justify-between mt-10">
            <Button
              variant="outline"
              onClick={handlePreviousLesson}
              disabled={currentLessonIndex === 0}
            >
              Previous Lesson
            </Button>

            <div className="flex space-x-3">
              {moduleCompleted && moduleId < 6 && (
                <Button
                  onClick={handleNextModule}
                  className="bg-accent hover:bg-accent-dark text-white"
                >
                  Next Module
                </Button>
              )}

              <Button
                onClick={handleNextLesson}
                disabled={currentLessonIndex === lessons.length - 1 && allLessonsCompleted}
              >
                {currentLessonIndex < lessons.length - 1
                  ? "Next Lesson"
                  : completedLessons[currentLesson.id]
                    ? "Module Completed"
                    : "Complete Module"
                }
              </Button>
            </div>
          </div>

          {moduleCompleted && (
            <Card className="mt-8 p-6 bg-accent bg-opacity-10 border-accent">
              <h3 className="font-heading text-xl font-bold mb-3 text-accent">
                🎉 Module Completed!
              </h3>
              <p className="text-neutral-medium mb-4">
                Great work completing this module! You've made significant progress in your Stoic Seller journey.
              </p>
              <div className="flex space-x-3">
                <Button
                  variant="outline"
                  onClick={() => setLocation("/")}
                >
                  Back to Dashboard
                </Button>
                {moduleId < 6 && (
                  <Button
                    onClick={handleNextModule}
                    className="bg-accent hover:bg-accent-dark text-white"
                  >
                    Continue to Module {moduleId + 1}
                  </Button>
                )}
              </div>
            </Card>
          )}
        </div>
      </div>
    </div>
  );
};

export default ModuleContent;

client/src/components/modules/ModulePrev.content:
import React from 'react';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Lock, Eye, CheckCircle, Clock } from "lucide-react";

interface Module {
  id: number;
  title: string;
  description: string;
  imageUrl?: string;
  order: number;
}

interface ModulePreviewProps {
  module: Module;
  isAuthenticated: boolean;
  isCompleted?: boolean;
  onLogin: () => void;
  onModuleClick: (moduleId: number) => void;
}

const ModulePreview: React.FC<ModulePreviewProps> = ({ 
  module, 
  isAuthenticated, 
  isCompleted = false,
  onLogin,
  onModuleClick 
}) => {
  const canAccess = isAuthenticated || module.order === 1; // First module always accessible as preview

  const handleClick = () => {
    if (!isAuthenticated && module.order > 1) {
      onLogin();
    } else {
      onModuleClick(module.id);
    }
  };

  const getStatusIcon = () => {
    if (!isAuthenticated && module.order > 1) {
      return <Lock className="w-5 h-5 text-gray-400" />;
    }
    if (isCompleted) {
      return <CheckCircle className="w-5 h-5 text-green-500" />;
    }
    if (canAccess) {
      return <Eye className="w-5 h-5 text-blue-500" />;
    }
    return <Clock className="w-5 h-5 text-gray-400" />;
  };

  const getStatusText = () => {
    if (!isAuthenticated && module.order > 1) {
      return "Sign in to unlock";
    }
    if (isCompleted) {
      return "Completed";
    }
    if (canAccess) {
      return module.order === 1 && !isAuthenticated ? "Preview Available" : "Available";
    }
    return "Locked";
  };

  return (
    <Card 
      className={`cursor-pointer transition-all duration-200 hover:shadow-lg ${
        !canAccess ? 'opacity-75' : ''
      } ${isCompleted ? 'border-green-200 bg-green-50' : ''}`}
      onClick={handleClick}
    >
      {module.imageUrl && (
        <div className="relative">
          <img 
            src={module.imageUrl} 
            alt={module.title}
            className={`w-full h-48 object-cover rounded-t-lg ${
              !canAccess ? 'filter grayscale' : ''
            }`}
          />
          {!canAccess && (
            <div className="absolute inset-0 bg-black bg-opacity-30 flex items-center justify-center rounded-t-lg">
              <Lock className="w-8 h-8 text-white" />
            </div>
          )}
        </div>
      )}

      <CardHeader>
        <div className="flex items-center justify-between">
